import './MaskField.scss';

import type { ChangeEvent } from 'react';
import React, { forwardRef, useImperativeHandle, useRef } from 'react';

import type { MaskFieldProps } from './MaskField.types';
import { NewMaskField } from './NewMaskField';
import { OldMaskField } from './OldMaskField';

export const MaskField = forwardRef<HTMLInputElement, MaskFieldProps>(
	(
		{
			size = 'medium',
			autoComplete = 'off',
			inputClassName: externalInputClassName,
			fullWidth = false,
			error = false,
			disabled = false,
			dataTestId = 'TextField',
			isClickableAdornment = true,
			maskConfig,
			maskedInstance,
			onChange,
			onMaskRef,
			onComplete,
			...props
		},
		ref,
	) => {
		const localRef = useRef<HTMLInputElement>(null);
		useImperativeHandle(ref, () => localRef.current);

		if (maskedInstance) {
			// OldMaskField ожидает onChange с одним аргументом (event)
			const handleOldOnChange =
				typeof onChange === 'function' ? (onChange as (event: ChangeEvent<HTMLInputElement>) => void) : undefined;

			return (
				<OldMaskField
					ref={localRef}
					size={size}
					autoComplete={autoComplete}
					inputClassName={externalInputClassName}
					fullWidth={fullWidth}
					error={error}
					disabled={disabled}
					dataTestId={dataTestId}
					isClickableAdornment={isClickableAdornment}
					maskedInstance={maskedInstance}
					onChange={handleOldOnChange}
					{...props}
				/>
			);
		}

		// NewMaskField ожидает onChange с тремя аргументами (value, unmaskedValue, event)
		const handleNewOnChange =
			typeof onChange === 'function'
				? (onChange as (value: string, unmaskedValue: string, event: InputEvent) => void)
				: undefined;

		return (
			<NewMaskField
				ref={localRef}
				size={size}
				autoComplete={autoComplete}
				inputClassName={externalInputClassName}
				fullWidth={fullWidth}
				error={error}
				disabled={disabled}
				dataTestId={dataTestId}
				isClickableAdornment={isClickableAdornment}
				maskConfig={maskConfig}
				onChange={handleNewOnChange}
				onMaskRef={onMaskRef}
				onComplete={onComplete}
				{...props}
			/>
		);
	},
);
